vector<int> Solution::maxDepthAfterSplit(string seq) {
    vector<int> res;
    int count = 0;
    for (char c : seq) {
        if (c == '(') {
            res.push_back(count & 1);
            count++;
        } else {
            res.push_back(count & 1);
            count--;
        }
    }
    return res;
}
